        "id": "ai_rich_text_steps",
        "type": "rich_text",
        "variant": "default",
        "props": {
          "eyebrow": "Key Strategy",
          "heading": "Validate Location Demand First",
          "body": {
            "version": 1,
            "nodes": [
              {
                "type": "paragraph",
                "text": "Before purchasing vending machines, successful operators emphasize validating demand at potential locations. Acquiring machines without a secured, high-traffic site is a common startup pitfall."
              },
              {
                "type": "heading",
                "level": 3,
                "text": "Primary Demand Signals to Watch"
              },
              {
                "type": "list",
                "style": "bullet",
                "items": [
                  "Foot traffic: Active pedestrian movement in the immediate area.",
                  "Dwell time: Locations where people naturally wait or gather.",
                  "Existing food options: Gaps in local dining choices make vending highly attractive."
                ]
              }
            ]
          }
        }
      },
      "sourceDocumentIds": [
        "11111111-1111-4111-8111-111111111111"
