    {
      "block": {
        "id": "ai_faq_vending",
        "type": "faq",
        "variant": "accordion",
        "props": {
          "heading": "Frequently Asked Questions",
          "items": [
            {
              "question": "Should I buy vending machines before finding a location?",
              "answer": "No. New vending operators should validate location demand before buying machines to ensure an active customer base."
            },
            {
              "question": "What are the strongest indicators of location demand?",
              "answer": "The strongest signals of location demand are foot traffic, dwell time, and the lack of existing nearby food options."
            }
          ]
        }
      },
